-- Backup Full Database Schema - NewsLan
-- Generated by Antigravity
-- This schema includes all tables, constraints, extensions, RLS policies, and triggers.

-- 1. EXTENSIONS
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- 2. INDEPENDENT TABLES & PARENTS
-- Profiles (Supabase Auth link)
CREATE TABLE IF NOT EXISTS public.profiles (
  id uuid NOT NULL PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  username text UNIQUE,
  full_name text,
  avatar_url text,
  role text DEFAULT 'member'::text CHECK (role = ANY (ARRAY['guest'::text, 'member'::text, 'subscriber'::text, 'writer'::text, 'admin'::text])),
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Advertisements (Parent to categories and ad_products)
CREATE TABLE IF NOT EXISTS public.advertisements (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text NOT NULL,
  type text NOT NULL CHECK (type = ANY (ARRAY['image'::text, 'html'::text, 'product_list'::text])),
  image_url text,
  link_url text,
  html_content text,
  placement text NOT NULL CHECK (placement = ANY (ARRAY['header_bottom'::text, 'article_before'::text, 'article_middle'::text, 'article_after'::text, 'sidebar'::text, 'section_sidebar'::text, 'feed_between'::text, 'skin_left'::text, 'skin_right'::text])),
  is_active boolean DEFAULT true,
  width integer,
  height integer,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Categories (Depends on advertisements for sidebar ads)
CREATE TABLE IF NOT EXISTS public.categories (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  slug text NOT NULL UNIQUE,
  description text,
  show_on_home boolean DEFAULT true,
  display_order integer DEFAULT 0,
  bg_color text DEFAULT '#E11D48'::text,
  sidebar_ad_id uuid REFERENCES public.advertisements(id) ON DELETE SET NULL,
  sidebar_ad_2_id uuid REFERENCES public.advertisements(id) ON DELETE SET NULL,
  sidebar_ad_3_id uuid REFERENCES public.advertisements(id) ON DELETE SET NULL,
  created_at timestamp with time zone DEFAULT now()
);

-- Product Categories
CREATE TABLE IF NOT EXISTS public.product_categories (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL UNIQUE,
  slug text NOT NULL UNIQUE,
  icon text NOT NULL,
  color text NOT NULL,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Products (Depends on product_categories)
CREATE TABLE IF NOT EXISTS public.products (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name text NOT NULL,
  description text,
  image_url text,
  price_range text,
  category_id uuid REFERENCES public.product_categories(id) ON DELETE SET NULL,
  created_at timestamp with time zone DEFAULT now()
);

-- 3. DEPENDENT TABLES (CHILDREN)
-- Ad Products Junction
CREATE TABLE IF NOT EXISTS public.ad_products (
  ad_id uuid NOT NULL REFERENCES public.advertisements(id) ON DELETE CASCADE,
  product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
  display_order integer DEFAULT 0,
  PRIMARY KEY (ad_id, product_id)
);

-- Affiliate Links
CREATE TABLE IF NOT EXISTS public.affiliate_links (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  product_id uuid REFERENCES public.products(id) ON DELETE CASCADE,
  store_name text NOT NULL,
  url text NOT NULL,
  click_count integer DEFAULT 0,
  created_at timestamp with time zone DEFAULT now()
);

-- Articles
CREATE TABLE IF NOT EXISTS public.articles (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text NOT NULL,
  slug text NOT NULL UNIQUE,
  content text NOT NULL,
  excerpt text,
  featured_image text,
  category_id uuid REFERENCES public.categories(id) ON DELETE SET NULL,
  author_id uuid REFERENCES public.profiles(id) ON DELETE SET NULL,
  is_premium boolean DEFAULT false,
  is_published boolean DEFAULT false,
  is_breaking boolean DEFAULT false,
  views_count integer DEFAULT 0,
  seo_title text,
  seo_description text,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  source_url text,
  product_placement character varying DEFAULT 'after'::character varying CHECK (product_placement::text = ANY (ARRAY['middle'::character varying, 'after'::character varying]::text[])),
  focus_keyword text
);

-- Article Products Junction
CREATE TABLE IF NOT EXISTS public.article_products (
  article_id uuid NOT NULL REFERENCES public.articles(id) ON DELETE CASCADE,
  product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
  PRIMARY KEY (article_id, product_id)
);

-- AI Auto Jobs
CREATE TABLE IF NOT EXISTS public.ai_auto_jobs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name character varying NOT NULL,
  task_key character varying NOT NULL UNIQUE,
  theme text NOT NULL,
  category_id uuid REFERENCES public.categories(id) ON DELETE SET NULL,
  style character varying DEFAULT 'Formal'::character varying,
  model_type character varying DEFAULT 'Breaking News'::character varying,
  generate_image boolean DEFAULT true,
  is_published boolean DEFAULT true,
  is_active boolean DEFAULT true,
  last_run_at timestamp without time zone,
  last_run_status character varying,
  total_runs integer DEFAULT 0,
  total_articles_generated integer DEFAULT 0,
  articles_per_run integer DEFAULT 1,
  created_at timestamp without time zone DEFAULT now(),
  updated_at timestamp without time zone DEFAULT now(),
  target_language text DEFAULT 'id'::text
);

-- RSS Auto Jobs
CREATE TABLE IF NOT EXISTS public.rss_auto_jobs (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  name character varying NOT NULL,
  task_key character varying NOT NULL UNIQUE,
  rss_url text NOT NULL,
  category_id uuid REFERENCES public.categories(id) ON DELETE SET NULL,
  is_published boolean DEFAULT true,
  max_articles_per_run integer DEFAULT 3,
  is_active boolean DEFAULT true,
  last_run_at timestamp without time zone,
  last_run_status character varying,
  last_run_articles integer DEFAULT 0,
  total_runs integer DEFAULT 0,
  total_articles_published integer DEFAULT 0,
  show_source_attribution boolean DEFAULT true,
  use_ai_image boolean DEFAULT false,
  created_at timestamp without time zone DEFAULT now(),
  updated_at timestamp without time zone DEFAULT now(),
  target_language text DEFAULT 'id'::text,
  writing_style character varying DEFAULT 'Professional'::character varying,
  article_model character varying DEFAULT 'Straight News'::character varying,
  job_type character varying DEFAULT 'standard'::character varying,
  search_keyword text,
  trend_region text DEFAULT 'local'::text,
  trend_niche text DEFAULT 'any'::text,
  thumbnail_priority text DEFAULT 'ai_priority'::text
);

-- Analytics Events
CREATE TABLE IF NOT EXISTS public.analytics_events (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  event_type text NOT NULL,
  target_id uuid NOT NULL,
  user_id uuid REFERENCES public.profiles(id) ON DELETE SET NULL,
  metadata jsonb,
  created_at timestamp with time zone DEFAULT now()
);

-- Complaints
CREATE TABLE IF NOT EXISTS public.complaints (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id uuid REFERENCES public.profiles(id) ON DELETE CASCADE,
  title text NOT NULL,
  description text NOT NULL,
  image_url text,
  status text DEFAULT 'pending'::text CHECK (status = ANY (ARRAY['pending'::text, 'processing'::text, 'resolved'::text, 'rejected'::text])),
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Shorts
CREATE TABLE IF NOT EXISTS public.shorts (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text,
  video_url text NOT NULL,
  thumbnail_url text,
  views_count integer DEFAULT 0,
  created_at timestamp with time zone DEFAULT now()
);

-- Short Products Junction
CREATE TABLE IF NOT EXISTS public.short_products (
  short_id uuid NOT NULL REFERENCES public.shorts(id) ON DELETE CASCADE,
  product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
  PRIMARY KEY (short_id, product_id)
);

-- WP Import Log
CREATE TABLE IF NOT EXISTS public.wp_import_log (
  wp_post_id integer NOT NULL PRIMARY KEY,
  article_id uuid REFERENCES public.articles(id) ON DELETE CASCADE,
  imported_at timestamp with time zone DEFAULT now()
);

-- 4. OTHER MISC TABLES
-- Banners
CREATE TABLE IF NOT EXISTS public.banners (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  title text,
  image_url text NOT NULL,
  link_url text,
  display_order integer DEFAULT 0,
  is_active boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);

-- Navigation Links
CREATE TABLE IF NOT EXISTS public.navigation_links (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  label text NOT NULL,
  url text NOT NULL,
  icon text,
  display_order integer DEFAULT 0,
  is_active boolean DEFAULT true,
  location text DEFAULT 'main'::text,
  created_at timestamp with time zone NOT NULL DEFAULT timezone('utc'::text, now())
);

-- Pages (Supports static pages like About, Privacy)
CREATE TABLE IF NOT EXISTS public.pages (
  id uuid NOT NULL DEFAULT uuid_generate_v4() PRIMARY KEY,
  title text NOT NULL,
  slug text NOT NULL UNIQUE,
  content text NOT NULL,
  is_published boolean DEFAULT true,
  is_footer boolean DEFAULT false,
  created_at timestamp with time zone NOT NULL DEFAULT timezone('utc'::text, now()),
  updated_at timestamp with time zone NOT NULL DEFAULT timezone('utc'::text, now())
);

-- Site Settings
CREATE TABLE IF NOT EXISTS public.site_settings (
  id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  setting_key text NOT NULL UNIQUE,
  setting_value text NOT NULL,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now()
);


