-- Profiles Policies
CREATE POLICY "Public profiles are viewable by everyone" ON public.profiles FOR SELECT USING (true);
CREATE POLICY "Users can update own profile" ON public.profiles FOR UPDATE USING (auth.uid() = id);

-- Categories Policies
CREATE POLICY "Categories are viewable by everyone" ON public.categories FOR SELECT USING (true);
CREATE POLICY "Admins can manage categories" ON public.categories FOR ALL USING (
  EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin')
);

-- Articles Policies
CREATE POLICY "Published non-premium articles are viewable by everyone" ON public.articles FOR SELECT USING (is_published = true AND is_premium = false);
CREATE POLICY "Premium articles are viewable by subscribers and admins" ON public.articles FOR SELECT USING (
  is_published = true AND is_premium = true AND (
    EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role IN ('subscriber', 'admin'))
  )
);
CREATE POLICY "Writers can manage their own articles" ON public.articles FOR ALL USING (author_id = auth.uid());
CREATE POLICY "Admins can manage all articles" ON public.articles FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- Products & Affiliate Links
CREATE POLICY "Products and links are viewable by everyone" ON public.products FOR SELECT USING (true);
CREATE POLICY "Admins can manage products" ON public.products FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "Affiliate links are viewable by everyone" ON public.affiliate_links FOR SELECT USING (true);
CREATE POLICY "Admins can manage affiliate links" ON public.affiliate_links FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- Video Shorts
CREATE POLICY "Shorts are viewable by everyone" ON public.shorts FOR SELECT USING (true);
CREATE POLICY "Admins can manage shorts" ON public.shorts FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "Short products are viewable by everyone" ON public.short_products FOR SELECT USING (true);
CREATE POLICY "Admins can manage short products" ON public.short_products FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- Article Products
CREATE POLICY "Article products are viewable by everyone" ON public.article_products FOR SELECT USING (true);
CREATE POLICY "Admins can manage article products" ON public.article_products FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- Advertisements & Banners
CREATE POLICY "Ads are viewable by everyone" ON public.advertisements FOR SELECT USING (true);
CREATE POLICY "Admins can manage ads" ON public.advertisements FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "Ad products are viewable by everyone" ON public.ad_products FOR SELECT USING (true);
CREATE POLICY "Admins can manage ad products" ON public.ad_products FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "Banners are viewable by everyone" ON public.banners FOR SELECT USING (is_active = true);
CREATE POLICY "Admins can manage banners" ON public.banners FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- Site Settings & Pages
CREATE POLICY "Allow public read for site_settings" ON public.site_settings FOR SELECT USING (true);
CREATE POLICY "Allow authenticated update for site_settings" ON public.site_settings FOR ALL USING (auth.role() = 'authenticated');
CREATE POLICY "Allow public read access to published pages" ON public.pages FOR SELECT USING (is_published = true);
CREATE POLICY "Allow authenticated users full access to pages" ON public.pages FOR ALL TO authenticated USING (true) WITH CHECK (true);

-- Complaints
CREATE POLICY "Users can insert their own complaints" ON public.complaints FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can view their own complaints" ON public.complaints FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Admins can view all complaints" ON public.complaints FOR SELECT USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));
CREATE POLICY "Admins can update complaint status" ON public.complaints FOR UPDATE USING (EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin'));

-- AI & RSS Jobs
CREATE POLICY "Allow authenticated users to manage AI jobs" ON public.ai_auto_jobs FOR ALL TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Allow public to read active AI jobs by task_key" ON public.ai_auto_jobs FOR SELECT TO public USING (is_active = true);
CREATE POLICY "Allow authenticated users to view RSS jobs" ON public.rss_auto_jobs FOR SELECT TO authenticated USING (true);
CREATE POLICY "Allow authenticated users to insert RSS jobs" ON public.rss_auto_jobs FOR INSERT TO authenticated WITH CHECK (true);
CREATE POLICY "Allow authenticated users to update RSS jobs" ON public.rss_auto_jobs FOR UPDATE TO authenticated USING (true) WITH CHECK (true);
CREATE POLICY "Allow authenticated users to delete RSS jobs" ON public.rss_auto_jobs FOR DELETE TO authenticated USING (true);
CREATE POLICY "Allow public to read active jobs by task_key" ON public.rss_auto_jobs FOR SELECT TO public USING (is_active = true);

-- Product Categories
CREATE POLICY "Allow public read access for product_categories" ON public.product_categories FOR SELECT USING (true);
CREATE POLICY "Allow full access for authenticated users on product_categories" ON public.product_categories FOR ALL USING (auth.role() = 'authenticated');

-- 6. FUNCTIONS & TRIGGERS
-- Auto-create profile on signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, avatar_url, role)
  VALUES (new.id, new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'avatar_url', 'member');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
